operation.add:
// Завантаження мовних змінних для OCMod
$this->load->language('extension/payment/alliance');
$data['text_select_for_return'] = $this->language->get('text_select_for_return');
$data['text_already_returned'] = $this->language->get('text_already_returned');
$data['text_order_fully_refunded'] = $this->language->get('text_order_fully_refunded');
$data['text_refund_shipping_cost'] = $this->language->get('text_refund_shipping_cost');
$data['text_please_select_products'] = $this->language->get('text_please_select_products');
$data['text_confirm_return_requests'] = $this->language->get('text_confirm_return_requests');
$shipping_match = $this->language->get('text_shipping_match') ? $this->language->get('text_shipping_match') : 'shipping';

// Додаємо дані про повернення без зміни core-файлу
$data['returned_products'] = [];
$returned_query = $this->db->query("SELECT product_id FROM " . DB_PREFIX . "return WHERE order_id = '" . (int)$this->request->get['order_id'] . "'");
if ($returned_query->num_rows) {
    foreach ($returned_query->rows as $row) {
        $data['returned_products'][] = $row['product_id'];
    }
}

$res_shipping = $this->db->query("SELECT return_id FROM " . DB_PREFIX . "return WHERE order_id = '" . (int)$this->request->get['order_id'] . "' AND comment LIKE '%" . $this->db->escape($shipping_match) . "%'");
$data['shipping_returned'] = $res_shipping->num_rows;
